sys_script_include.script:
var IncentNowPortalUtils = Class.create();
IncentNowPortalUtils.prototype = {
    initialize: function() {
    },

	applyPlaceholders: function(form) {

        if (!form || !form._fields)
            return form;

        for (var key in form._fields) {

            var field = form._fields[key];

            if (field.hint) {
                field.placeholder = field.hint;
            }
        }

        return form; // always return
    },

    getFieldMapping: function(table, view) {
        var result = [];

        // 1. Get List Definition
        var listGR = new GlideRecord('sys_ui_list');
		listGR.addEncodedQuery("name="+GlideStringUtil.escapeQueryTermSeparator(table)+"^view.name="+GlideStringUtil.escapeQueryTermSeparator(view)+"^ORview.title="+GlideStringUtil.escapeQueryTermSeparator(view)+"^sys_user=NULL");
        listGR.orderByDesc("sys_updated_on");
        listGR.query();

		//gs.addInfoMessage("LIst gr "+listGR.getEncodedQuery()+ " -- "+listGR.getRowCount());
        if (!listGR.next()) {
            return result; // no list found
        }
		gs.info("List Id "+listGR.sys_id);
        var listId = listGR.sys_id;

        // 2. Get List Elements (fields)
        var elementGR = new GlideRecord('sys_ui_list_element');
        elementGR.addQuery('list_id', listId);
        elementGR.orderBy('position');
        elementGR.query();

        while (elementGR.next()) {
            var fieldName = elementGR.element.toString();

            // 3. Get Label from Dictionary
            var label = this._getFieldLabel(table, fieldName);

            result.push({
                column_name: fieldName,
                column_label: label
            });
        }

        return result;
    },

    _getFieldLabel: function(table, field) {
        var dictGR = new GlideRecord('sys_dictionary');
        dictGR.addQuery('name', table);
        dictGR.addQuery('element', field);
        dictGR.query();

        if (dictGR.next()) {
            return dictGR.column_label.toString();
        }

        return field;
    },

	hasExactRole : function(roleName) {
		var userId = gs.getUserID();
		var hasExactRole = false;

		var userRole = new GlideRecord('sys_user_has_role');
		userRole.addQuery('user', userId);
		userRole.addQuery('role.name', roleName);
		userRole.addQuery('inherited', false);
		userRole.query();

		if (userRole.hasNext()) {
			hasExactRole = true;
		}

		return hasExactRole;
	},

	getCurrencies: function()
	{

		var currencyGR = new GlideRecordSecure('fx_currency');
		currencyGR.addQuery('active', true);
		currencyGR.orderBy('code');
		currencyGR.query();
		var currencies = [];
		while (currencyGR.next()) {
			currencies.push({
				label: currencyGR.code + ' - ' + currencyGR.name + " ("+currencyGR.symbol+")",
				value: currencyGR.symbol.toString()
			});
		}
		return currencies;

	},

getBusinessGroupAdmins:function(planbu)
{
	var approvers = [];
    var businessUnit = planbu;

    var salesUserGR = new GlideRecord('x_ctans_incentnow_user_profile');
    salesUserGR.addQuery('business_unit', businessUnit);
    salesUserGR.query();

    while (salesUserGR.next()) {

        var userId = salesUserGR.getValue('user');
        var bgAdmin = new GlideRecord('sys_user_has_role');
        bgAdmin.addQuery('user', userId);
        bgAdmin.addQuery('role.name', 'x_ctans_incentnow.business_group_admin');
        bgAdmin.setLimit(1);
        bgAdmin.query();

        if (bgAdmin.next()) {
            approvers.push(userId);
        }    
    }

    return approvers.join(',');

},


    type: 'IncentNowPortalUtils'
};
